function intersection<T>(a: Set<T>, b: Set<T>): Set<T> {
  const result: Set<T> = new Set();
  for (const val of a) {
    if (b.has(val)) result.add(val);
  }
  return result;
}

const s1: Set<number> = new Set([1, 2, 3, 4]);
const s2: Set<number> = new Set([3, 4, 5, 6]);
console.log([...intersection(s1, s2)]);  // [3, 4]

