function union<T>(a: Set<T>, b: Set<T>): Set<T> {
  const result: Set<T> = new Set(a)
  for (const val of b) {
    result.___(val)
  }
  return result
}

function difference<T>(a: Set<T>, b: Set<T>): Set<T> {
  const result: Set<T> = new Set()
  for (const val of a) {
    if (!b.___(val)) result.add(val)
  }
  return result
}

const s1: Set<number> = new Set([1, 2, 3])
const s2: Set<number> = new Set([2, 3, 4])

console.log([...union(s1, s2)].sort().join(","))
console.log([...difference(s1, s2)].join(","))

